import { UmbTextStyles } from "@umbraco-cms/backoffice/style";
import { css, html, LitElement } from "@umbraco-cms/backoffice/external/lit";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import type {
  UserFormSecurity,
  UserGroupFormSecurity,
} from "@umbraco-forms/generated";
import type { FormsInputFolderElement } from "@umbraco-forms/components";
import type { UUIBooleanInputEvent } from "@umbraco-cms/backoffice/external/uui";
import type { PackagePermissionsSecurityBase } from "../../../entities.js";
import type { FormsSecurityUserWorkspaceContext } from "../../security-user-workspace.context.js";
import type { FormsSecurityUserGroupWorkspaceContext } from "../../security-user-group-workspace.context.js";

export abstract class UmbWorkspaceViewSecurityPermissionsBaseElement<
  ContextType extends
    | FormsSecurityUserWorkspaceContext
    | FormsSecurityUserGroupWorkspaceContext
> extends UmbElementMixin(LitElement) {
  workspaceContext?: ContextType;

  abstract onPackagePermissionsChange(
    e: UUIBooleanInputEvent,
    key: keyof PackagePermissionsSecurityBase
  ): void;

  abstract observeSecurityItem(): void;

  constructor(contextAlias: string) {
    super();

    this.consumeContext(contextAlias, (instance) => {
      this.workspaceContext = instance as ContextType;
      this.observeSecurityItem();
    });
  }

  renderSecurityTable(
    formsSecurity: Array<UserFormSecurity | UserGroupFormSecurity>
  ) {
    if (!this.workspaceContext) return;

    return html`<uui-box
      .headline=${this.localize.term("formSecurity_manageIndividualFormsLabel")}
    >
      <umb-property-layout
        alias="forms"
        .label=${this.localize.term("sections_forms")}
        .description=${this.localize.term(
          "formSecurity_manageIndividualFormsDescription"
        )}
      >
        <form-security-table
          slot="editor"
          .records=${formsSecurity ?? []}
          .set=${(formId: string, value: boolean) =>
            this.workspaceContext?.setFormSecurityAccess(formId, value)}
          .toggle=${(formId: string) =>
            this.workspaceContext?.toggleFormSecurityAccess(formId)}
        ></form-security-table>
      </umb-property-layout>
    </uui-box>`;
  }

  renderStartFolders(startFolderIds: Array<string>) {
    if (!this.workspaceContext) return;

    const onChange = (event: Event) => {
      const target = event.target as FormsInputFolderElement;
      this.workspaceContext?.setProperty("startFolderIds", target.selection);
      this.dispatchEvent(new CustomEvent("valueChange"));
    };

    return html`<uui-box
      .headline=${this.localize.term("formSecurity_startFolders")}
    >
      <umb-property-layout
        alias="startFolders"
        .label=${this.localize.term("formSecurity_selectNewStartFolders")}
        .description=${this.localize.term(
          "formSecurity_startFoldersDescription"
        )}
      >
        <forms-input-folder
          .selection=${startFolderIds}
          @change=${onChange}
          slot="editor"
        ></forms-input-folder>
      </umb-property-layout>
    </uui-box>`;
  }

  renderToggles(security?: PackagePermissionsSecurityBase) {
    if (!security) return;

    return html`<uui-box headline=${this.localize.term("formSecurity_packagePermissions")}>
      <umb-property-layout
        alias="manageForms"
        .label=${this.localize.term("formSecurity_manageFormsLabel")}
        .description=${this.localize.term(
          "formSecurity_manageFormsDescription"
        )}
      >
        <uui-toggle
          slot="editor"
          ?checked=${security.manageForms}
          @change=${(e: UUIBooleanInputEvent) =>
            this.onPackagePermissionsChange(e, "manageForms")}
        ></uui-toggle>
      </umb-property-layout>
      <umb-property-layout
        alias="viewEntries"
        .label=${this.localize.term("formSecurity_viewEntriesLabel")}
        .description=${this.localize.term(
          "formSecurity_viewEntriesDescription"
        )}
      >
        <uui-toggle
          slot="editor"
          ?checked=${security.viewEntries}
          @change=${(e: UUIBooleanInputEvent) =>
            this.onPackagePermissionsChange(e, "viewEntries")}
        ></uui-toggle>
      </umb-property-layout>
      <umb-property-layout
        alias="editEntries"
        .label=${this.localize.term("formSecurity_editEntriesLabel")}
        .description=${this.localize.term(
          "formSecurity_editEntriesDescription"
        )}
      >
        <uui-toggle
          slot="editor"
          ?checked=${security.editEntries}
          ?disabled=${!security.viewEntries}
          @change=${(e: UUIBooleanInputEvent) =>
            this.onPackagePermissionsChange(e, "editEntries")}
        ></uui-toggle>
      </umb-property-layout>
      <umb-property-layout
        alias="editEntries"
        .label=${this.localize.term("formSecurity_deleteEntriesLabel")}
        .description=${this.localize.term(
          "formSecurity_deleteEntriesDescription"
        )}
      >
        <uui-toggle
          slot="editor"
          ?checked=${security.deleteEntries}
          ?disabled=${!security.viewEntries}
          @change=${(e: UUIBooleanInputEvent) =>
            this.onPackagePermissionsChange(e, "deleteEntries")}
        ></uui-toggle>
      </umb-property-layout>
      <umb-property-layout
        alias="manageWorkflows"
        .label=${this.localize.term("formSecurity_manageWorkflowsLabel")}
        .description=${this.localize.term(
          "formSecurity_manageWorkflowsDescription"
        )}
      >
        <uui-toggle
          slot="editor"
          ?checked=${security.manageWorkflows}
          @change=${(e: UUIBooleanInputEvent) =>
            this.onPackagePermissionsChange(e, "manageWorkflows")}
        ></uui-toggle>
      </umb-property-layout>
      <umb-property-layout
        alias="manageDatasources"
        .label=${this.localize.term("formSecurity_manageDatasourcesLabel")}
        .description=${this.localize.term(
          "formSecurity_manageDatasourcesDescription"
        )}
      >
        <uui-toggle
          slot="editor"
          ?checked=${security.manageDataSources}
          @change=${(e: UUIBooleanInputEvent) =>
            this.onPackagePermissionsChange(e, "manageDataSources")}
        ></uui-toggle>
      </umb-property-layout>
      <umb-property-layout
        alias="managePrevalueSources"
        .label=${this.localize.term("formSecurity_managePrevalueSourcesLabel")}
        .description=${this.localize.term(
          "formSecurity_managePrevalueSourcesDescription"
        )}
      >
        <uui-toggle
          slot="editor"
          ?checked=${security.managePreValueSources}
          @change=${(e: UUIBooleanInputEvent) =>
            this.onPackagePermissionsChange(e, "managePreValueSources")}
        ></uui-toggle>
      </umb-property-layout>
    </uui-box>`;
  }

  static styles = [
    UmbTextStyles,
    css`
      :host {
        display: block;
        padding: var(--uui-size-layout-1);
      }

      uui-box {
        margin-bottom: var(--uui-size-6);
      }
    `,
  ];
}
